const { Pool } = require('pg');
const dotenv = require('dotenv');

dotenv.config();

const pool = new Pool({
  user: process.env.DB_USER,
  host: process.env.DB_HOST,
  database: process.env.DB_DATABASE,
  password: process.env.DB_PASSWORD,
  port: process.env.DB_PORT,
});

const createTableUsers = () => {
  const query = `CREATE TABLE IF NOT EXISTS users (
                    id SERIAL PRIMARY KEY,
                    username VARCHAR(255) UNIQUE NOT NULL,
                    email VARCHAR(255) UNIQUE NOT NULL
                  )`;
  pool.query(query);
};

const createTablePosts = () => {
  const query = `CREATE TABLE IF NOT EXISTS posts (
                    id SERIAL PRIMARY KEY,
                    title TEXT NOT NULL,
                    content TEXT NOT NULL,
                    author_id INTEGER REFERENCES users(id)
                  )`;
  pool.query(query);
};

const insertUser = (username, email) => {
  const query = 'INSERT INTO users(username, email) VALUES($1, $2)';
  pool.query(query, [username, email]);
};

const insertPost = (title, content, authorId) => {
  const query = 'INSERT INTO posts(title, content, author_id) VALUES($1, $2, $3)';
  pool.query(query, [title, content, authorId]);
};

// Add more CRUD operations as needed for your application

pool.on('connect', () => {
  createTableUsers();
  createTablePosts();
});